// src/pages/HomePage.js
import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useSensor } from '../hooks/useSensor';
import './HomePage.css';

const HomePage = () => {
    const navigate = useNavigate();
    const { status, loading } = useSensor();

    return (
        <div className="home-page">
            <div className="hero-section">
                <h2>Secure Electronic Health Records</h2>
                <p>Protected by fingerprint authentication</p>
            </div>

            <div className="status-card">
                <h3>System Status</h3>
                {loading ? (
                    <p>Checking sensor...</p>
                ) : (
                    <>
                        <p className={status.connected ? 'success' : 'error'}>
                            Sensor: {status.connected ? '✅ Connected' : '❌ Disconnected'}
                        </p>
                        <p>Port: {status.port}</p>
                    </>
                )}
            </div>

            <div className="actions">
                <button 
                    className="btn btn-primary" 
                    onClick={() => navigate('/login')}
                >
                    Login
                </button>
                <button 
                    className="btn btn-secondary"
                    onClick={() => navigate('/register')}
                >
                    Register
                </button>
            </div>
        </div>
    );
};

export default HomePage;
